Action.Str:
var tailclip_text = '';
var tailclip_reason = '';
var previousClip = global('PREV_CLIP') || '';

if (typeof cl_text === 'string' && cl_text.length > 0) {
    tailclip_text = cl_text;
}

if (!tailclip_text) {
    tailclip_reason = 'missing';
} else if (tailclip_text === previousClip) {
    tailclip_reason = 'duplicate';
}
